def compress(s):
    if not s:
        return ""
    out = []
    prev, run = s[0], 1
    for ch in s[1:]:
        if ch == prev:
            run += 1
        else:
            out.append(prev + (str(run) if run > 1 else ""))
            prev, run = ch, 1
    out.append(prev + (str(run) if run > 1 else ""))
    return "".join(out)
